"""
fernsehserien_scraper - single-file build (v0.1.1)

Generated by build_single_file.py - copy this one file into another project
instead of pip-installing the full package. Still requires:

    pip install requests beautifulsoup4

Scraper for fernsehserien.de.

fernsehserien.de has no official API (confirmed: no API is advertised anywhere on the
site, and every existing integration - Kodi/XBMC addons, MediaElch, tinyMediaManager -
is itself an unofficial scraper). `robots.txt` only disallows the GPTBot user agent,
not general crawling, so reading public pages here is not against their stated crawl
policy - but community reports (Kodi forums, GitHub issues) note the site has blocked
known bot/automation user agents in the past and structures its HTML in a way that's
apparently meant to make scraping harder. Because of that, this scraper:

  - parses the fully-rendered page *text* with regular expressions instead of relying
    on CSS classes/IDs, which are more likely to be obfuscated or to change silently;
  - rate-limits itself between requests (see `delay` in `FernsehserienScraper.__init__`);
  - uses a normal browser-like User-Agent by default (a plain "python-requests" UA is
    exactly the kind of thing that's been reported blocked) - override it via the
    `user_agent` argument if you'd rather identify your script explicitly.

Two page types are covered, matching what this site adds *on top of* aggregator APIs
like JustWatch/Watchmode (which fernsehserien.de's own streaming-provider data comes
from anyway, per their footer credit "Streaming-Daten in Zusammenarbeit mit JustWatch"):

  - `show_info(slug)`  - the main "Infos" page: title, episode/season counts, German
    streaming premiere (date + provider) and original TV premiere (date + channel +
    language).
  - `sendetermine(slug)` - the "Sendetermine" page: German TV broadcast schedule.

`slug` is the part of the URL after fernsehserien.de/, e.g. "breaking-bad" or
"perfect-crown" - fernsehserien.de's own site search is a JavaScript-driven
autocomplete widget, not a plain crawlable URL, so there's no reliable "search by
title" here; look the slug up manually (visit the site, or google
"<title> site:fernsehserien.de") and pass it in directly.

Verified against live pages while building this: `show_info()`'s premiere-date
parsing (checked against fernsehserien.de/perfect-crown) and `sendetermine()`'s
"currently not airing" case (checked against fernsehserien.de/breaking-bad/sendetermine).
NOT verified: `sendetermine()`'s output for a show that IS currently airing with
upcoming broadcast dates - I didn't have a live example of that page's exact text
while building this. `raw_text` is always included in the result so you can see
exactly what was parsed (or not) and extend the regex if it doesn't match your case.
"""

import re
import time

import requests
from bs4 import BeautifulSoup

BASE_URL = "https://www.fernsehserien.de"

_DEFAULT_USER_AGENT = (
	"Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 "
	"(KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36"
)

_DATE = r"\d{2}\.\d{2}\.\d{4}"


class FernsehserienError(Exception):
	"""Raised for HTTP errors or when a page doesn't look like a valid show page."""

	def __init__(self, message, status_code=None):
		self.status_code = status_code
		super().__init__(message)


class FernsehserienScraper:
	"""Small, rate-limited scraper for fernsehserien.de show pages."""

	def __init__(self, delay=1.5, user_agent=None, session=None, timeout=10):
		'''
		Args:
			delay: minimum seconds between requests made through this instance. Please
				don't set this to 0 for anything but a one-off manual check - the site
				is a small, independently run German site (imfernsehen GmbH & Co. KG),
				not a hyperscale API, and has reportedly blocked aggressive bots before.
			user_agent: override the default browser-like User-Agent string.
			session: reuse an existing `requests.Session`, otherwise a new one is created.
			timeout: per-request timeout in seconds.
		'''
		self.delay = delay
		self.timeout = timeout
		self.session = session or requests.Session()
		self.session.headers.update({
			"User-Agent": user_agent or _DEFAULT_USER_AGENT,
			"Accept-Language": "de-DE,de;q=0.9",
		})
		self._last_request_at = 0.0

	def _get_soup(self, path):
		wait = self.delay - (time.time() - self._last_request_at)
		if wait > 0:
			time.sleep(wait)

		url = path if path.startswith("http") else BASE_URL + path
		r = self.session.get(url, timeout=self.timeout)
		self._last_request_at = time.time()

		if r.status_code == 404:
			raise FernsehserienError(
				"No page at {} - check the slug (the part of the URL after "
				"fernsehserien.de/).".format(url),
				status_code=404,
			)
		if not r.ok:
			raise FernsehserienError(
				"HTTP {} for {}".format(r.status_code, url), status_code=r.status_code
			)
		return BeautifulSoup(r.text, "html.parser")

	def show_info(self, slug):
		''' Parse the main "Infos" page for a show/movie.

		Args:
			slug: the URL slug, e.g. "breaking-bad", "perfect-crown".

		Returns:
			dict: {
				"slug": str,
				"title": str,
				"episode_count": int | None,
				"season_count": int | None,
				"german_streaming_premiere": {
					"provider": {"name": str, "country": "de", "firstEpisode": "DD.MM.YYYY"}
				} | None,
				"original_tv_premiere": {"date": "DD.MM.YYYY", "channel": str, "language": str} | None,
				"raw_text": str,  # full page text, for inspecting anything not parsed above
			}
		'''
		soup = self._get_soup("/" + slug.strip("/"))
		text = soup.get_text(" ", strip=True)
		text = re.sub(r"\s+", " ", text)

		title_tag = soup.find("h1")
		title = title_tag.get_text(strip=True) if title_tag else slug

		result = {
			"slug": slug,
			"title": title,
			"episode_count": None,
			"season_count": None,
			"german_streaming_premiere": None,
			"original_tv_premiere": None,
			"raw_text": text,
		}

		m = re.search(r"bisher (\d+) Folgen? in (\d+) Staffeln?", text)
		if m:
			result["episode_count"] = int(m.group(1))
			result["season_count"] = int(m.group(2))

		m = re.search(
			r"Deutsche Streaming-Premiere\s*({date})\s*(.*?)(?=Original-TV-Premiere|$)".format(date=_DATE),
			text,
		)
		if m:
			provider_name = m.group(2).strip(" -")
			result["german_streaming_premiere"] = {
				"provider": {
					"name": provider_name.lower(),
					"country": "de",
					"firstEpisode": m.group(1),
				}
			}

		m = re.search(
			r"Original-TV-Premiere\s*({date})\s*(.*?)\(([^()]+)\)".format(date=_DATE),
			text,
		)
		if m:
			result["original_tv_premiere"] = {
				"date": m.group(1),
				"channel": m.group(2).strip(" -"),
				"language": m.group(3).strip(),
			}

		return result

	def sendetermine(self, slug):
		''' Parse the "Sendetermine" (German TV broadcast schedule) page.

		Args:
			slug: the URL slug, e.g. "breaking-bad".

		Returns:
			dict: {
				"slug": str,
				"currently_airing": bool,
				"last_aired": {"date": "DD.MM.YYYY", "channel": str} | None,
				"upcoming": list[dict],  # see note below - not verified live
				"raw_text": str,
			}

			`upcoming` is a best-effort scan for "DD.MM.YYYY ... bei CHANNEL" patterns
			in the page text for currently-airing shows. This case wasn't confirmed
			against a live example while building this scraper - if it comes back
			empty for a show you know is airing, inspect `raw_text` and adjust the
			regex in this method.
		'''
		soup = self._get_soup("/{}/sendetermine".format(slug.strip("/")))
		text = soup.get_text(" ", strip=True)
		text = re.sub(r"\s+", " ", text)

		result = {
			"slug": slug,
			"currently_airing": None,
			"last_aired": None,
			"upcoming": [],
			"raw_text": text,
		}

		if re.search(r"läuft aktuell nicht im Fernsehen", text):
			result["currently_airing"] = False
			m = re.search(
				r"Zuletzt lief die (?:Serie|Sendung|Film) am ({date}) bei ([^.]+)\.".format(date=_DATE),
				text,
			)
			if m:
				result["last_aired"] = {"date": m.group(1), "channel": m.group(2).strip()}
		else:
			result["currently_airing"] = True
			for m in re.finditer(r"({date})[^.]*?bei ([^.,]+)".format(date=_DATE), text):
				result["upcoming"].append({"date": m.group(1), "channel": m.group(2).strip()})

		return result


__version__ = "0.1.1"
